import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  Users, 
  ShieldCheck, 
  User, 
  Mail, 
  Phone, 
  Trash2, 
  Loader2, 
  CalendarDays 
} from 'lucide-react';

const UserManagement = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  // Đã xóa selectedUser và showEditModal để sửa lỗi ESLint

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/users');
      setUsers(res.data);
      setLoading(false);
    } catch (error) {
      console.error('Lỗi tải users:', error);
      setLoading(false);
    }
  };

  const handleRoleChange = async (userId, newRole) => {
    if (window.confirm(`Bạn có chắc muốn thay đổi quyền thành ${newRole.toUpperCase()}?`)) {
      try {
        await axios.put(`http://localhost:5000/api/admin/users/${userId}/role`, { role: newRole });
        alert('Cập nhật quyền thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Cập nhật thất bại'));
      }
    }
  };

  const handleDeleteUser = async (userId) => {
    if (window.confirm('Cảnh báo: Hành động này không thể hoàn tác. Bạn có chắc chắn muốn xóa?')) {
      try {
        await axios.delete(`http://localhost:5000/api/admin/users/${userId}`);
        alert('Xóa người dùng thành công!');
        fetchUsers();
      } catch (error) {
        alert('Lỗi: ' + (error.response?.data?.message || 'Xóa thất bại'));
      }
    }
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('vi-VN');
  };

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh', gap: '10px' }}>
      <Loader2 className="animate-spin" /> Đang tải dữ liệu...
    </div>
  );

  return (
    <div style={{ padding: '20px' }}>
      <h1 style={{ display: 'flex', alignItems: 'center', gap: '10px', marginBottom: '25px' }}>
        <Users size={32} /> Quản lý người dùng
      </h1>
      
      {/* Thống kê nhanh */}
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', 
        gap: '20px', 
        marginBottom: '30px' 
      }}>
        <div style={statCardStyle}>
          <Users color="#6366f1" />
          <div>
            <p style={{ margin: 0, color: '#666' }}>Tổng Users</p>
            <h2 style={{ margin: 0 }}>{users.length}</h2>
          </div>
        </div>
        <div style={statCardStyle}>
          <ShieldCheck color="#f59e0b" />
          <div>
            <p style={{ margin: 0, color: '#666' }}>Admin</p>
            <h2 style={{ margin: 0 }}>{users.filter(u => u.role === 'admin').length}</h2>
          </div>
        </div>
        <div style={statCardStyle}>
          <User color="#10b981" />
          <div>
            <p style={{ margin: 0, color: '#666' }}>Thành viên</p>
            <h2 style={{ margin: 0 }}>{users.filter(u => u.role === 'user').length}</h2>
          </div>
        </div>
      </div>

      {/* Bảng users */}
      <table className="admin-table" style={{ width: '100%', borderCollapse: 'collapse', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}>
        <thead style={{ backgroundColor: '#f8f9fa' }}>
          <tr>
            <th style={thStyle}>Người dùng</th>
            <th style={thStyle}>Liên hệ</th>
            <th style={thStyle}>Vai trò</th>
            <th style={thStyle}>Ngày tham gia</th>
            <th style={{ ...thStyle, textAlign: 'center' }}>Hành động</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            <tr key={user.id} style={{ borderBottom: '1px solid #edf2f7' }}>
              <td style={tdStyle}>
                <div style={{ fontWeight: '600' }}>{user.fullname}</div>
                <div style={{ fontSize: '12px', color: '#718096' }}>ID: #{user.id}</div>
              </td>
              <td style={tdStyle}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '14px' }}>
                  <Mail size={14} /> {user.email}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '5px', fontSize: '14px', color: '#4a5568' }}>
                  <Phone size={14} /> {user.phone || 'N/A'}
                </div>
              </td>
              <td style={tdStyle}>
                <select
                  value={user.role}
                  onChange={(e) => handleRoleChange(user.id, e.target.value)}
                  style={{
                    padding: '6px 12px',
                    borderRadius: '20px',
                    border: 'none',
                    fontSize: '13px',
                    fontWeight: '600',
                    cursor: 'pointer',
                    backgroundColor: user.role === 'admin' ? '#fef3c7' : '#dcfce7',
                    color: user.role === 'admin' ? '#92400e' : '#166534'
                  }}
                >
                  <option value="user">User</option>
                  <option value="admin">Admin</option>
                </select>
              </td>
              <td style={tdStyle}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <CalendarDays size={14} /> {formatDate(user.created_at)}
                </div>
              </td>
              <td style={{ ...tdStyle, textAlign: 'center' }}>
                <button 
                  onClick={() => handleDeleteUser(user.id)}
                  style={{
                    background: 'none',
                    border: 'none',
                    color: (user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1) ? '#cbd5e0' : '#ef4444',
                    cursor: (user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1) ? 'not-allowed' : 'pointer',
                    display: 'flex',
                    alignItems: 'center',
                    gap: '4px',
                    margin: '0 auto'
                  }}
                  disabled={user.role === 'admin' && users.filter(u => u.role === 'admin').length <= 1}
                >
                  <Trash2 size={18} />
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

// CSS Styles
const statCardStyle = {
  display: 'flex',
  alignItems: 'center',
  gap: '15px',
  padding: '20px',
  backgroundColor: '#fff',
  borderRadius: '12px',
  boxShadow: '0 1px 3px 0 rgb(0 0 0 / 0.1)'
};

const thStyle = {
  padding: '12px 15px',
  textAlign: 'left',
  color: '#4a5568',
  fontSize: '14px',
  fontWeight: '600'
};

const tdStyle = {
  padding: '15px',
  verticalAlign: 'middle'
};

export default UserManagement;
